function OnUpdate(doc, meta) {

    try {

        // -------------------------------------------------------
        // SAFETY GATES
        // -------------------------------------------------------

        if (!doc || !doc.eventType || !meta || !meta.id) {
            log("DROP_INVALID_DOC", meta && meta.id, doc);
            return;
        }

        if (meta.id.startsWith("eventing::")) {
            log("SKIP_INTERNAL_DOC", meta.id);
            return;
        }

        log("EVENT_RECEIVED", meta.id, doc.eventType);

        handleEvent(doc, meta);

    } catch (e) {
        log("FATAL_ERROR", meta.id, e);
    }
}


function handleEvent(doc, meta) {

    var type = doc.eventType;

    // -------------------------------------------------------
    // SHADOW WRITE
    // -------------------------------------------------------
    try {
        writeShadowSafe(doc, meta);
        log("SHADOW_OK", meta.id);
    } catch (e) {
        log("SHADOW_FAIL", meta.id, e);
    }

    // -------------------------------------------------------
    // COUNTER UPDATE
    // -------------------------------------------------------
    try {
        incrementCounterSafe(type);
        log("COUNTER_OK", type);
    } catch (e) {
        log("COUNTER_FAIL", meta.id, e);
    }
}


function writeShadowSafe(doc, meta) {

    var shadow;

    try {
        shadow = JSON.parse(JSON.stringify(doc));
    } catch (e) {
        shadow = doc;
    }

    shadow._source = "eventing";

    try {
        shadow_bucket[meta.id] = shadow;
        log("SHADOW_WRITTEN", meta.id);
    } catch (e) {
        log("SHADOW_WRITE_FAIL", meta.id, e);
    }
}


function incrementCounterSafe(type) {

    var key = "event::" + type;

    log("COUNTER_READ_ATTEMPT", key);

    var counter = null;

    // -------------------------------------------------------
    // READ COUNTER (FIXED: Eventing KV binding access)
    // -------------------------------------------------------
    try {
        counter = meta_bucket[key];
        log("COUNTER_READ_OK", key, counter);
    } catch (e) {
        log("COUNTER_MISS_OR_ERROR", key, e);
        counter = null;
    }

    // -------------------------------------------------------
    // INITIALIZE IF EMPTY
    // -------------------------------------------------------
    if (!counter || typeof counter.count !== "number") {
        counter = { count: 0 };
        log("COUNTER_INIT", key);
    }

    counter.count++;

    // -------------------------------------------------------
    // WRITE COUNTER (FIXED: Eventing KV binding access)
    // -------------------------------------------------------
    try {
        meta_bucket[key] = counter;
        log("COUNTER_WRITTEN", key, counter.count);
    } catch (e) {
        log("COUNTER_WRITE_FAIL", key, e);
    }
}
